     `}function EI(){if(!window.AppAuth?.getUser())return"";const e=typeof window.app_renderBudgetHeadOptions=="function"?window.app_renderBudgetHeadOptions(""):'<option value="UNALLOCATED">Unallocated / To Be Mapped</option>';return`
